PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?collaborator ?label WHERE {
  wd:Q20553371 wdt:P175 | wdt:P162 | wdt:P3614 ?collaborator .
  FILTER(?collaborator != wd:Q13560423)
  OPTIONAL {
    ?collaborator rdfs:label ?label .
    FILTER(LANG(?label) = 'en')
  }
}

